diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..f7f0f740a9f8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3011,6 +3011,51 @@ struct DecomposedSelect {
   Value *FalseVal = nullptr;
 };
 } // namespace
+/// Look for patterns like:
+///   %sel1 = select i1 %c1, i32 %a, i32 %b
+///   %sel2 = select i1 %c1, i32 %b, i32 %a
+///   %ret = select i1 %c2, i32 %sel1, i32 %sel2
+/// and rewrite it as:
+///   %xor = xor i1 %c1, %c2
+///   %ret = select i1 %xor, i32 %b, i32 %a
+static Instruction *foldSelectOfSymmetricSelects(SelectInst &SI,
+                                                  InstCombiner::BuilderTy &Builder) {
+  Value *Cond = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // Both operands must be selects.
+  auto *TrueSI = dyn_cast<SelectInst>(TrueVal);
+  auto *FalseSI = dyn_cast<SelectInst>(FalseVal);
+  if (!TrueSI || !FalseSI)
+    return nullptr;
+
+  // Both inner selects must have the same condition.
+  Value *InnerCond = TrueSI->getCondition();
+  if (InnerCond != FalseSI->getCondition())
+    return nullptr;
+
+  // Conditions must have the same type to create XOR.
+  if (InnerCond->getType() != Cond->getType())
+    return nullptr;
+
+  // Check for symmetric pattern: select(c, a, b) and select(c, b, a)
+  Value *A = TrueSI->getTrueValue();
+  Value *B = TrueSI->getFalseValue();
+  if (FalseSI->getTrueValue() != B || FalseSI->getFalseValue() != A)
+    return nullptr;
+
+  // Profitability check - both inner selects should have single use
+  // (the outer select). This ensures we're reducing instruction count.
+  if (!TrueSI->hasOneUse() || !FalseSI->hasOneUse())
+    return nullptr;
+  // Create xor of conditions: xor c1, c2
+  Value *XorCond = Builder.CreateXor(InnerCond, Cond);
+  XorCond->takeName(Cond);
+
+  // Create new select: select (xor c1, c2), b, a
+  return SelectInst::Create(XorCond, B, A, SI.getName());
+}

 /// Look for patterns like
 ///   %outer.cond = select i1 %inner.cond, i1 %alt.cond, i1 false
@@ -3987,6 +4032,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  if (Instruction *I = foldSelectOfSymmetricSelects(SI, Builder))
+    return I;
+
   if (Instruction *I = foldNestedSelects(SI, Builder))
     return I;

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

